public void testThisTypeOfFunction5() throws Exception {
  testTypes(
      "/** @constructor */ function F() {}" +
      "F.prototype.method = function() {};" +
      "var obj = new F();" +
      "obj.method();");
}

public void testThisTypeOfFunction6() throws Exception {
  testTypes(
      "/** @constructor */ function F() {}" +
      "/** @type {function(this:F, number)} */ function f(x) {}" +
      "var obj = new F();" +
      "obj.f = f;" +
      "obj.f(5);");
}

public void testThisTypeOfFunction7() throws Exception {
  testTypes(
      "/** @constructor */ function F() {}" +
      "F.prototype.data = 10;" +
      "F.prototype.get = function() { return this.data; };" +
      "var arr = [new F()];" +
      "var getter = arr[0].get;" +
      "getter();",
      "\"function (this:F): ?\" must be called with a \"this\" type");
}

public void testThisTypeOfFunction8() throws Exception {
  testTypes(
      "/** @constructor */ function F() {}" +
      "/** @type {function(this:F)} */ var func;" +
      "var condition = true;" +
      "(condition ? func : func)();",
      "\"function (this:F): ?\" must be called with a \"this\" type");
}
